// BS-SLA-Monitor (BS-FUNNEL M4, 2026-07-19). Buckets bs_payment_settled -> bs_compliance_report
// by age since payment. Writes bs_sla_status action_type per paid row per bucket, idempotent
// by (task_id, bucket).
const URL='https://srhpmvfdzllsovluahjf.supabase.co';
const KEY='eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InNyaHBtdmZkemxsc292bHVhaGpmIiwicm9sZSI6ImFub24iLCJpYXQiOjE3ODE4MzIxNTEsImV4cCI6MjA5NzQwODE1MX0.9qcmlp3UzC6qdpLmsEKc4Zohc4_EajUuXVP2cGsXEN0';
const H={'apikey':KEY,'Authorization':'Bearer '+KEY,'Content-Type':'application/json'};
async function get(p){return await this.helpers.httpRequest({method:'GET',url:URL+'/rest/v1/'+p,headers:H,json:true});}
async function post(p,body){await this.helpers.httpRequest({method:'POST',url:URL+'/rest/v1/'+p,headers:{...H,Prefer:'return=minimal'},body,json:true});}
const now=Date.now();
const cutoffIso=new Date(now-30*24*3600*1000).toISOString();
const pays=await get.call(this,'bs_event_log?select=id,task_id,created_at,payload&action_type=eq.bs_payment_settled&created_at=gt.'+cutoffIso+'&limit=200');
const reports=await get.call(this,'bs_event_log?select=task_id,payload,created_at&action_type=eq.bs_compliance_report&created_at=gt.'+cutoffIso+'&limit=500');
const already=await get.call(this,'bs_event_log?select=payload&action_type=eq.bs_sla_status&created_at=gt.'+cutoffIso+'&limit=1000');
const seen=new Set(already.map(x=>((x.payload||{}).sid+':'+((x.payload||{}).bucket))).filter(k=>k));
// index reports by session_id (from payload) OR task_id
const reportedSids=new Set();
for(const r of reports){
  const p=r.payload||{}; const sid=p.session_id||p.sid||r.task_id;
  if(sid) reportedSids.add(sid);
}
const out={on_track:0,sla_breach:0,skipped:0};
for(const pay of pays){
  const p=pay.payload||{};
  const sid=p.session_id||p.sid||pay.task_id;
  const ageH=(now-Date.parse(pay.created_at))/3600000;
  const delivered=reportedSids.has(sid);
  let bucket;
  if(delivered) bucket=ageH<=48?'on_track':'sla_breach_delivered_late';
  else if(ageH>48) bucket='sla_breach_processing';
  else{out.skipped++;continue;}
  const key=sid+':'+bucket;
  if(seen.has(key)){out.skipped++;continue;}
  await post.call(this,'bs_event_log',{action_type:'bs_sla_status',target:'sla_monitor',
    payload:{sid,bucket,age_h:Math.round(ageH),paid_at:pay.created_at,delivered},livemode:true});
  out[bucket]=(out[bucket]||0)+1;
}
return [{json:out}];
